import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ShieldCheck, Shield, Pencil, Trash2, Settings2, Lock } from 'lucide-react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { toast } from 'sonner';

import { roleService } from '@/api/auth/roleService';
import { getApiErrorMessage } from '@/api/app/apiError';
import { queryKeys } from '@/lib/queryKeys';
import { ROUTES } from '@/lib/routes';
import { useHarmonyServerTable } from '@/hooks/useHarmonyServerTable';
import { HarmonyTable, type HarmonyColumn } from '@/components/ui/harmony-table';
import { HarmonyAlertDialog } from '@/components/ui/harmony-alert-dialog';
import { HarmonyRichTextCell } from '@/components/ui/harmony-table-richtext-cell';
import { RoleFormDialog } from '@/features/roles/components/RoleFormDialog';
import { PermissionGate } from '@/components/shared/PermissionGate';
import { PERMISSIONS } from '@/constants/permissions';
import { Button } from '@/shadcn/components/ui/button';
import { Badge } from '@/shadcn/components/ui/badge';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/shadcn/components/ui/tooltip';

import type { Role } from '@/types/role';

interface RolesFilters {
  active: string;
  [key: string]: string;
}

const Roles = () => {
  const navigate     = useNavigate();
  const queryClient  = useQueryClient();

  const [createOpen,   setCreateOpen]   = useState(false);
  const [editTarget,   setEditTarget]   = useState<Role | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<Role | null>(null);
  const [formError,    setFormError]    = useState<string | null>(null);
  const [search,       setSearch]       = useState('');

  const server = useHarmonyServerTable<RolesFilters>({
    defaultFilters: { active: '' },
  });

  const activeParam = server.filterValues.active === 'true'
    ? true
    : server.filterValues.active === 'false'
      ? false
      : undefined;

  const { data, isLoading, isError, error } = useQuery({
    queryKey: queryKeys.roles.list(server.filterValues, server.sort, server.sortOrder, server.pageIndex, server.pageSize, search),
    queryFn: () => roleService.getRoles({
      pageIndex: server.pageIndex,
      pageSize:  server.pageSize,
      sort:      server.sort,
      sortOrder: server.sortOrder,
      search:    search || undefined,
      active:    activeParam,
    }),
  });

  const invalidate = () => queryClient.invalidateQueries({ queryKey: queryKeys.roles.base() });

  const createMutation = useMutation({
    mutationFn: (formData: Record<string, unknown>) => roleService.createRole(formData),
    onSuccess: () => {
      invalidate();
      setCreateOpen(false);
      setFormError(null);
      toast.success('Role created successfully.');
    },
    onError: (err) => setFormError(getApiErrorMessage(err)),
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, formData }: { id: string; formData: Record<string, unknown> }) => roleService.updateRole(id, formData),
    onSuccess: () => {
      invalidate();
      setEditTarget(null);
      setFormError(null);
      toast.success('Role updated successfully.');
    },
    onError: (err) => setFormError(getApiErrorMessage(err)),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => roleService.deleteRole(id),
    onSuccess: () => {
      invalidate();
      setDeleteTarget(null);
      toast.success('Role deleted successfully.');
    },
    onError: (err) => toast.error(getApiErrorMessage(err)),
  });

  const actionsColumn: HarmonyColumn<Role> = {
    key: 'actions',
    header: 'Actions',
    width: 100,
    sortable: false,
    resizable: false,
    cellClass: 'rdg-cell-actions',
    renderCell: ({ row }) => (
      <TooltipProvider>
        <div className="flex items-center gap-0.5">
          <PermissionGate permission={PERMISSIONS.RolePermission.Read} mode="disable">
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  size="icon-xs"
                  variant="ghost"
                  className="text-muted-foreground hover:text-foreground"
                  onClick={(e) => { e.stopPropagation(); navigate(ROUTES.roleConfiguration(row.id)); }}
                >
                  <Settings2 size={12} />
                </Button>
              </TooltipTrigger>
              <TooltipContent>Configure</TooltipContent>
            </Tooltip>
          </PermissionGate>
          <PermissionGate permission={PERMISSIONS.Role.Update} mode="disable">
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  size="icon-xs"
                  variant="ghost"
                  className="text-muted-foreground hover:text-foreground"
                  onClick={(e) => { e.stopPropagation(); setFormError(null); setEditTarget(row); }}
                >
                  <Pencil size={12} />
                </Button>
              </TooltipTrigger>
              <TooltipContent>Edit</TooltipContent>
            </Tooltip>
          </PermissionGate>
          {!row.isBuiltIn && (
            <PermissionGate permission={PERMISSIONS.Role.Delete} mode="disable">
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    size="icon-xs"
                    variant="ghost"
                    className="text-muted-foreground hover:text-destructive hover:bg-destructive/10"
                    onClick={(e) => { e.stopPropagation(); setDeleteTarget(row); }}
                  >
                    <Trash2 size={12} />
                  </Button>
                </TooltipTrigger>
                <TooltipContent>Delete</TooltipContent>
              </Tooltip>
            </PermissionGate>
          )}
        </div>
      </TooltipProvider>
    ),
  };

  const columns: HarmonyColumn<Role>[] = [
    {
      key: 'id',
      header: 'ID',
      width: 272,
      sortable: false,
      renderCell: ({ row }) => row.id,
    },
    {
      key: 'name',
      header: 'Role',
      width: 200,
      sortParam: 'name',
      renderCell: ({ row }) => (
        <button
          type="button"
          className="flex items-center gap-2 w-full text-left hover:opacity-75 transition-opacity"
          onClick={(e) => { e.stopPropagation(); navigate(ROUTES.roleConfiguration(row.id)); }}
        >
          <div className="p-1.5 bg-primary/10 rounded-md text-primary border border-primary/20 shrink-0">
            <Shield size={13} />
          </div>
          <span className="font-semibold text-foreground underline underline-offset-2 decoration-muted-foreground/40">{row.name}</span>
          {row.isBuiltIn && (
            <Tooltip>
              <TooltipTrigger asChild>
                <span className="inline-flex items-center gap-1 px-1.5 py-0.5 rounded text-[10px] font-medium bg-muted text-muted-foreground border border-border shrink-0">
                  <Lock size={9} />
                  Built-in
                </span>
              </TooltipTrigger>
              <TooltipContent>This role is protected and cannot be deleted or deactivated.</TooltipContent>
            </Tooltip>
          )}
        </button>
      ),
    },
    {
      key: 'description',
      header: 'Description',
      fill: true,
      sortable: false,
      renderCell: ({ row }) => <HarmonyRichTextCell html={row.description} />,
    },
    {
      key: 'active',
      header: 'Active',
      width: 90,
      sortParam: 'active',
      renderCell: ({ row }) => row.active
        ? <Badge variant="outline" className="border-emerald-300 bg-emerald-50 text-emerald-700 dark:border-emerald-800 dark:bg-emerald-950/40 dark:text-emerald-400">Active</Badge>
        : <Badge variant="outline" className="text-muted-foreground">Inactive</Badge>,
    },
    {
      key: 'userCount',
      header: 'Users',
      width: 70,
      sortable: false,
      renderCell: ({ row }) => row.userCount ?? 0,
    },
    {
      key: 'permissionCount',
      header: 'Permissions',
      width: 110,
      sortable: false,
      renderCell: ({ row }) => row.permissionCount ?? 0,
    },
    actionsColumn,
  ];

  return (
    <div className="page-wrapper flex flex-col" style={{ gap: 'var(--section-padding)' }}>

      {/* Header */}
      <div className="flex items-center gap-3">
        <div className="size-12 flex items-center justify-center rounded-(--radius-lg) bg-primary/10 shrink-0">
          <ShieldCheck className="w-7 h-7 text-primary" />
        </div>
        <div>
          <h1 className="page-title">Roles &amp; Permissions</h1>
          <p className="page-subtitle">Define and configure security roles and permissions.</p>
        </div>
      </div>

      {/* Table */}
      <HarmonyTable<Role>
        rows={data?.data ?? []}
        columns={columns}
        rowKeyGetter={(row) => row.id}
        loading={isLoading}
        error={isError ? (error as Error) : undefined}

        filterDefs={[
          {
            param: 'active',
            label: 'Status',
            type: 'select',
            options: [
              { value: 'true',  label: 'Active' },
              { value: 'false', label: 'Inactive' },
            ],
          },
        ]}
        filterValues={server.filterValues}
        onFilterChange={server.onFilterChange}

        sortColumns={server.sortColumns}
        onSortColumnsChange={server.onSortColumnsChange}

        onSearchChange={(q) => { setSearch(q); server.setPageIndex(1); }}
        searchDebounce={400}
        searchPlaceholder="Search roles…"

        dataActions={{
          extra: (
            <PermissionGate permission={PERMISSIONS.Role.Create}>
              <Button variant="default" size="sm" onClick={() => { setFormError(null); setCreateOpen(true); }}>
                New Role
              </Button>
            </PermissionGate>
          ),
        }}

        pagination={server.getPagination(data)}
      />

      {/* Create dialog */}
      <RoleFormDialog
        open={createOpen}
        onClose={() => setCreateOpen(false)}
        editingRole={null}
        onSubmit={(formData) => createMutation.mutate(formData)}
        error={formError}
        isSubmitting={createMutation.isPending}
      />

      {/* Edit dialog */}
      <RoleFormDialog
        open={editTarget !== null}
        onClose={() => setEditTarget(null)}
        editingRole={editTarget}
        onSubmit={(formData) => editTarget && updateMutation.mutate({ id: editTarget.id, formData })}
        error={formError}
        isSubmitting={updateMutation.isPending}
      />

      {/* Delete confirmation */}
      {deleteTarget && (
        <HarmonyAlertDialog
          open={!!deleteTarget}
          onOpenChange={(open) => { if (!open) setDeleteTarget(null); }}
          variant="danger"
          title="Delete Security Role"
          description={`This will permanently remove the "${deleteTarget.name}" role. Any users assigned to this role will lose the permissions it grants. This action cannot be undone.`}
          actionLabel="Delete Role"
          onAction={() => deleteTarget && deleteMutation.mutate(deleteTarget.id)}
          isActioning={deleteMutation.isPending}
        />
      )}
    </div>
  );
};

export default Roles;
